// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <string.h>
#define MAX 100005

int main() {
    int T, Q, N, X, Y, type, A, B, L, R, ans;
    char P[MAX];

    scanf("%d", &T);
    while (T--) {
        scanf("%s %d", P, &Q);
        N = strlen(P);
        A = 0; B = 0;
        while (Q--) {
            scanf("%d %d %d", &X, &Y, &type);
            L = (X + A) % N + 1;
            R = (Y + B) % N + 1;
            if (L > R) {
                int temp = L;
                L = R;
                R = temp;
            }
            ans = 0;
            for (int i = L - 1; i < R; i++) {
                for (int j = i; j < R; j++) {
                    int freq[26] = {0};
                    for (int k = i; k <= j; k++) {
                        freq[P[k] - 'a']++;
                    }
                    int balanced = 1;
                    for (int k = 0; k < 26; k++) {
                        if (freq[k] % 2 != 0) {
                            balanced = 0;
                            break;
                        }
                    }
                    if (balanced) {
                        ans++;
                    }
                }
            }
            if (type == 0) {
                printf("%d\n", ans);
            } else if (type == 1) {
                printf("%d\n", ans * 2);
            } else {
                printf("%d\n", ans * 3);
            }
            A = B;
            B = ans;
        }
    }
    return 0;
}

